import React from "react";
import KitsContainer from "../../helpers/FormContainer";
import {AutoComplete, useSeparator} from "@lmb-it/kitsconcertomobile";
import type { IAutoCompleteElement } from "@lmb-it/kitsconcerto-types";
import { useAutoCompleteLogic } from "../hooks/useAutoCompleteLogic";
import { useComponentDefaults, useResolvedStyle } from "../../../hooks";
import { useKitsTheme } from "../../../contexts/Theme";

const KitsAutoComplete = ({ ref, ...rawProps }: IAutoCompleteElement) => {
    const { mergedProps: props, themeStyle, elementStyles } = useComponentDefaults('AutoComplete', rawProps, 'Input');
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});
    const {
        id,
        rightAddon,
        leftAddon,
        errors,
        invalid,
        label,
        hideError,
        disabled,
        required,
        isFloatedLabel,
        inputSize = "md",
        forceSelection,
        completeMethod,
        helperText,
        withArrow,
        placeholder,
        isMultiple,
        localProps,
        delay,
        minLength,
        selectionLimit,
        showEmptyMessage,
        attached,
        containerStyle,
    } = props;

    const { nativeProps } = useSeparator<HTMLSelectElement>(props);

    const { resolveToken } = useKitsTheme();
    const primaryColor = resolveToken('primary');
    const borderColor = resolveToken('border');

    const {
        inputValue,
        setInputValue,
        filteredList,
        search,
        handleOnChange,
        list,
        childrenKey,
        labelKey,
    } = useAutoCompleteLogic({ isMultiple, forceSelection, completeMethod, ref });

    const hasThemeStyle = Object.keys(themeStyle).length > 0;


    const Element = <AutoComplete
        disabled={disabled}
        placeholder={placeholder}
        value={inputValue}
        forceSelection={forceSelection}
        suggestions={Array.isArray(filteredList) ? filteredList : list}
        completeMethod={search}
        dropdown={withArrow}
        multiple={isMultiple}
        field={labelKey}
        invalid={!!invalid}
        emptyMessage="No results found"
        {...(delay != null ? { delay } : {})}
        {...(minLength != null ? { minLength } : {})}
        {...(selectionLimit != null ? { selectionLimit } : {})}
        showEmptyMessage={showEmptyMessage ?? true}
        optionGroupChildren={childrenKey ?? undefined}
        optionGroupLabel={childrenKey ? labelKey : undefined}
        style={{ width: "100%", borderRadius: 0, border:'none', backgroundColor:'transparent' }}
        inputStyle={{ flexDirection: "row", borderRadius: 0, border:'none', width: "100%",backgroundColor:'transparent', ...(resolvedRootStyle || resolvedThemeStyle) }}
        onChange={(event) => {
            setInputValue(event.value);
            handleOnChange(event);
        }}
        {...(localProps ?? {})}
    />

    if (attached) {
        return Element;
    }

    return (
        <KitsContainer
            id={id}
            inputSize={inputSize}
            isFloatedLabel={isFloatedLabel}
            hideError={hideError}
            rightAddon={rightAddon}
            leftAddon={leftAddon}
            required={required}
            helperText={helperText}
            errors={errors}
            invalid={invalid}
            label={label}
            containerStyle={containerStyle}
            elementStyles={elementStyles}
        >
            {Element}
        </KitsContainer>
    );
};

export default KitsAutoComplete;
